sc mem flag open "[Area] â€¦ | Blocker for: â€¦" --name CC-001 [--feature <id>]
sc mem flag edit <flag_id> [--description "â€¦"] [--priority High] [--feature <id>]
sc mem flag close <flag_id> --notes "â€¦"

